-- Creare store di default
INSERT INTO `stores` (`id`, `name`, `address`, `isActive`)
VALUES ('default-store-001', 'Negozio Principale', 'Via Roma 1, Milano', true)
ON DUPLICATE KEY UPDATE `name` = `name`;

-- Associare tutti gli utenti esistenti allo store di default come admin
INSERT INTO `storeUsers` (`userId`, `storeId`, `role`)
SELECT `id`, 'default-store-001', 'admin'
FROM `users`
WHERE NOT EXISTS (
  SELECT 1 FROM `storeUsers` WHERE `storeUsers`.`userId` = `users`.`id`
);

-- Impostare preferredStoreId per tutti gli utenti
UPDATE `users` SET `preferredStoreId` = 'default-store-001' WHERE `preferredStoreId` IS NULL;

